```go
// interface/rest/middleware/auth.go

type Claims struct {
    UserID string
    Roles  []string
}

type contextKey string

const claimsKey contextKey = "claims"

func Authentication(verifier TokenVerifier) func(http.Handler) http.Handler {
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            token := extractBearerToken(r)
            if token == "" {
                respondError(w, http.StatusUnauthorized, "missing token")
                return
            }

            claims, err := verifier.Verify(r.Context(), token)
            if err != nil {
                respondError(w, http.StatusUnauthorized, "invalid token")
                return
            }

            ctx := context.WithValue(r.Context(), claimsKey, claims)
            next.ServeHTTP(w, r.WithContext(ctx))
        })
    }
}

func RequireRole(roles ...string) func(http.Handler) http.Handler {
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            if len(roles) == 0 {
                respondError(w, http.StatusInternalServerError, "no roles specified")
                return
            }

            claims := ClaimsFromContext(r.Context())
            if claims == nil {
                respondError(w, http.StatusUnauthorized, "not authenticated")
                return
            }

            for _, required := range roles {
                for _, actual := range claims.Roles {
                    if required == actual {
                        next.ServeHTTP(w, r)
                        return
                    }
