    isMember, err := i.members.IsMember(ctx, model.ProjectID(input.ProjectID), actor)
    if err != nil {
        return nil, fmt.Errorf("failed to check membership: %w", err)
    }
    if !isMember {
        return nil, ErrNotAuthorized
    }

